import { GoogleGenAI, Type } from "@google/genai";
import type { EventObject } from '../lib/types';
import type { Part } from "@google/genai";
import type { GCalEvent } from './googleCalendarService';


// The service will return a raw object without the `id` field.
// It will be added in App.tsx after receiving the data.
export type ApiEventObject = Omit<EventObject, 'id'>;

// FIX: Use process.env.API_KEY to align with the coding guidelines.
const getAiClient = () => {
    // FIX: Switched from import.meta.env.VITE_API_KEY to process.env.API_KEY to adhere to the coding guidelines.
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        // FIX: Updated error message to reflect the change to process.env.API_KEY.
        throw new Error("La variabile d'ambiente API_KEY non è impostata. Assicurati che sia configurata nell'ambiente di esecuzione.");
    }
    return new GoogleGenAI({ apiKey });
};

const eventSchema = {
    type: Type.OBJECT,
    properties: {
      subject: { type: Type.STRING, description: 'The title or subject of the event. This is a required field.' },
      startDate: { type: Type.STRING, description: 'The start date of the event. Normalize to YYYY-MM-DD format.' },
      startTime: { type: Type.STRING, description: 'The start time of the event. Normalize to HH:mm (24-hour) format.' },
      endDate: { type: Type.STRING, description: 'The end date of the event. Should be the same as startDate if not specified. Normalize to YYYY-MM-DD format.' },
      endTime: { type: Type.STRING, description: 'The end time of the event. If not specified, assume a 1-hour duration. Normalize to HH:mm (24-hour) format.' },
      description: { type: Type.STRING, description: 'A brief description of the event. Can be an empty string.' },
      location: { type: Type.STRING, description: 'The location of the event. Can be an empty string.' },
    },
    required: ['subject', 'startDate', 'startTime', 'endDate', 'endTime'],
  };

const getExtractionPrompt = (): string => {
  const currentYear = new Date().getFullYear();
  return `
Sei un assistente intelligente per l'estrazione di dati. Il tuo compito è analizzare il contenuto fornito ed estrarre tutti gli eventi in un formato JSON strutturato conforme allo schema fornito.

Segui queste regole con precisione:
1.  Il tuo output DEVE essere un array JSON valido di oggetti evento. Non includere altro testo, spiegazioni o formattazione markdown.
2.  Estrai i seguenti campi per ogni evento: subject, startDate, startTime, endDate, endTime, description, location.
3.  Sii molto flessibile con i formati di data e ora di input (es. GG/MM/AAAA, MM-GG-AAAA, AAAA.MM.GG, Mese GG, AAAA, 2pm, 14:00).
4.  Quando fornisci le date, normalizzale rigorosamente nel formato AAAA-MM-GG.
5.  Quando fornisci gli orari, normalizzale rigorosamente nel formato HH:mm (24 ore).
6.  Se un anno non è specificato per una data, supponi che l'anno corrente sia ${currentYear}.
7.  Se l'orario di fine o la durata di un evento non sono specificati, calcola un orario di fine che sia esattamente 1 ora dopo l'orario di inizio.
8.  Se una data di fine non è specificata, supponi che sia la stessa della data di inizio.
9.  Se un campo come 'description' o 'location' non è presente per un evento, devi restituire una stringa vuota "" per quel campo.
10. Il campo 'subject' è obbligatorio. Se non riesci a determinare un oggetto per una riga o una sezione, salta completamente quel record e non includerlo nell'array di output.
`;
};

const fileToGenerativePart = async (file: File): Promise<Part> => {
    const base64EncodedData = await new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = (e) => reject(e);
      reader.readAsDataURL(file);
    });

    return {
      inlineData: {
        mimeType: file.type,
        data: base64EncodedData
      }
    };
  };

export const extractEvents = async (input: File | string): Promise<ApiEventObject[]> => {
  if (!input) {
    throw new Error("L'input non può essere vuoto.");
  }

  try {
    const ai = getAiClient();

    const contents = typeof input === 'string'
      ? { parts: [{ text: input }] }
      : { parts: [await fileToGenerativePart(input)] };

    const systemInstruction = getExtractionPrompt();

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents,
      config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.ARRAY,
              items: eventSchema
          }
      }
    });

    try {
      const jsonText = (response.text ?? '').trim();
      if (!jsonText) {
        return [];
      }
      const parsedEvents: ApiEventObject[] = JSON.parse(jsonText);
      return parsedEvents;
    } catch (e) {
        console.error("Impossibile analizzare la risposta JSON dall'IA:", response.text);
        throw new Error("Il modello IA ha restituito una struttura dati non valida. Controlla il contenuto del file e riprova.");
    }
  } catch (err: any) {
      console.error("Errore API Gemini:", err);
      // Passa attraverso il messaggio di errore specifico della chiave API.
      // FIX: Updated the error message check to look for API_KEY instead of VITE_API_KEY.
      if (err.message?.includes('API_KEY non è impostata')) {
          throw err;
      }
      // Controlla errori specifici come sovraccarico o indisponibilità
      if (err.message && (err.message.includes('503') || /overload|unavailable|rate limit/i.test(err.message))) {
          throw new Error("Il servizio di intelligenza artificiale è attualmente sovraccarico o non disponibile. Per favore, attendi un momento e riprova.");
      }
      // Lancia un errore più generico per altri problemi API
      throw new Error("Si è verificato un errore di comunicazione con il servizio AI. Controlla la tua connessione o la configurazione della chiave API.");
  }
};

export const suggestCorrection = async (event: EventObject, fieldToCorrect: keyof Omit<EventObject, 'id'>): Promise<string | null> => {
  const ai = getAiClient();
  const systemInstruction = `
Sei un assistente intelligente per la correzione dei dati. Il tuo compito è correggere un campo specifico che è stato contrassegnato come non valido. Fornisci una correzione plausibile per il campo specificato.

Basandoti sul contesto dell'intero evento, suggerisci un valore corretto.
- Per le date (startDate, endDate), usa rigorosamente il formato GG-MM-AAAA.
- Per gli orari (startTime, endTime), usa rigorosamente il formato HH:mm.
- Sii il più logico possibile. Ad esempio, se la data di inizio è "30/02/2024", una buona correzione sarebbe "29-02-2024".

Restituisci SOLO un oggetto JSON con una singola chiave "suggestion" contenente il valore stringa corretto. Non includere altro testo o markdown.
`;
  const userPrompt = `
Dati originali dell'evento:
${JSON.stringify(event, null, 2)}

Il campo da correggere è: "${fieldToCorrect}".
Il valore non valido corrente è: "${event[fieldToCorrect]}".
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            suggestion: { type: Type.STRING }
          },
          required: ['suggestion']
        }
      }
    });

    const jsonText = (response.text ?? '').trim();
    if (!jsonText) {
      return null;
    }
    const parsedResponse = JSON.parse(jsonText);
    return parsedResponse.suggestion || null;

  } catch (e) {
    console.error("Impossibile ottenere il suggerimento di correzione dall'IA:", e);
    return null;
  }
};

export const findEventsToDelete = async (query: string, events: GCalEvent[]): Promise<string[]> => {
  if (!query) throw new Error("La query di ricerca non può essere vuota.");
  if (events.length === 0) return [];

  const ai = getAiClient();
  const systemInstruction = `
Sei un assistente intelligente per la pulizia di calendari. Il tuo compito è analizzare una query dell'utente e un elenco di eventi di Google Calendar (in formato JSON) e restituire gli ID degli eventi che corrispondono alla query.

Regole:
1. La tua risposta DEVE essere un array JSON valido contenente solo le stringhe degli ID degli eventi corrispondenti.
2. Interpreta il linguaggio naturale. Ad esempio, "riunioni vecchie" potrebbe significare eventi passati da molto tempo, "eventi vuoti" potrebbe indicare eventi senza altri partecipanti o descrizione.
3. Se la query è "tutti gli eventi con 'budget' nel titolo", restituisci gli ID di tutti gli eventi il cui 'summary' contiene la parola 'budget'.
4. Se nessun evento corrisponde, restituisci un array vuoto [].
5. Non includere altro testo, spiegazioni o markdown nella risposta. Solo l'array JSON di stringhe di ID.
`;

  const userPrompt = `
Query utente: "${query}"

Elenco eventi (considera solo i campi forniti):
${JSON.stringify(events.map(e => ({id: e.id, summary: e.summary, description: e.description, start: e.start, end: e.end, attendees: e.attendees})), null, 2)}
`;

  const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
          }
      }
  });

  try {
      const jsonText = (response.text ?? '').trim();
      if (!jsonText) return [];
      const parsedIds: string[] = JSON.parse(jsonText);
      return parsedIds;
  } catch (e) {
      console.error("Impossibile analizzare la risposta JSON degli ID evento dall'IA:", response.text);
      throw new Error("Il modello IA ha restituito una struttura dati non valida per gli ID evento.");
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import * as gcal from '../services/googleCalendarService';
import { Loader } from './Loader';
// FIX: Import SparklesIcon to resolve 'Cannot find name' error.
import { GoogleIcon, SearchIcon, Trash2Icon, SparklesIcon } from './Icons';
import { findEventsToDelete } from '../services/geminiService';

type GCalState = 'initial' | 'authenticating' | 'authenticated' | 'loading' | 'error';
interface GCalError { title: string; message: string; }
interface Calendar { id: string; summary: string; primary?: boolean; }

export const CleanupView: React.FC = () => {
    const [gcalState, setGCalState] = useState<GCalState>('initial');
    const [error, setError] = useState<GCalError | null>(null);
    const [user, setUser] = useState<{ email: string } | null>(null);
    const [calendars, setCalendars] = useState<Calendar[]>([]);
    const [selectedCalendarId, setSelectedCalendarId] = useState('');
    const [events, setEvents] = useState<gcal.GCalEvent[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [isSearching, setIsSearching] = useState(false);

    const handleGapiLoad = useCallback(async () => {
        try {
            await gcal.initGapiClient();
        } catch (err: any) {
            setError({ title: 'Errore di Inizializzazione', message: err.message });
            setGCalState('error');
        }
    }, []);

    useEffect(() => {
        const script = document.createElement('script');
        script.src = 'https://apis.google.com/js/api.js';
        // FIX: Cast window to any to access gapi, which is loaded from an external script.
        script.onload = () => (window as any).gapi.load('client', handleGapiLoad);
        script.async = true;
        document.body.appendChild(script);
        return () => { document.body.removeChild(script); };
    }, [handleGapiLoad]);

    const fetchInitialData = useCallback(async () => {
        try {
            const userInfoResponse = await gcal.getUserProfile();
            if (!userInfoResponse?.result?.email) throw new Error("Profilo utente non trovato.");
            setUser(userInfoResponse.result);

            const calendarList = await gcal.listCalendars();
            setCalendars(calendarList);
            const primaryCalendar = calendarList.find((c: Calendar) => c.primary) || calendarList[0];
            if (primaryCalendar) setSelectedCalendarId(primaryCalendar.id);

            setGCalState('authenticated');
        } catch (err: any) {
            setError({ title: 'Errore nel Caricamento Dati', message: err.message });
            setGCalState('error');
        }
    }, []);

    const handleTokenResponse = useCallback(async (tokenResponse: any) => {
        if (tokenResponse.error) {
            setError({ title: "Autenticazione Fallita", message: tokenResponse.error_description || "L'utente ha annullato l'accesso."});
            setGCalState('initial'); // Torna allo stato iniziale
            return;
        }
        if (tokenResponse.access_token) {
            // FIX: Cast window to any to access gapi, which is loaded from an external script.
            (window as any).gapi.client.setToken(tokenResponse);
            setGCalState('loading');
            await fetchInitialData();
        }
    }, [fetchInitialData]);

    const handleAuth = () => {
        setGCalState('authenticating');
        setError(null);
        gcal.handleAuthClick((token) => handleTokenResponse(token));
    };

    const handleSearch = async () => {
        if (!searchQuery.trim() || !selectedCalendarId) return;

        setIsSearching(true);
        setError(null);

        try {
            const now = new Date();
            const timeMin = new Date();
            timeMin.setFullYear(now.getFullYear() - 5); // Cerca negli ultimi 5 anni

            const fetchedEvents = await gcal.listEvents(selectedCalendarId, timeMin.toISOString(), now.toISOString());

            // Simula la ricerca AI
            const eventIdsToDelete = await findEventsToDelete(searchQuery, fetchedEvents);
            const foundEvents = fetchedEvents.filter(e => eventIdsToDelete.includes(e.id));
            setEvents(foundEvents);

        } catch (err: any) {
            setError({ title: 'Errore durante la ricerca', message: err.message });
        } finally {
            setIsSearching(false);
        }
    };


    if (gcalState === 'initial' || gcalState === 'authenticating') {
        return (
            <div className="text-center p-8 bg-card rounded-lg border border-border">
                <h2 className="text-2xl font-bold mb-3">Pulisci il tuo Calendario</h2>
                <p className="text-muted-foreground mb-6 max-w-xl mx-auto">
                    Connettiti al tuo account Google per trovare e rimuovere eventi superflui usando filtri potenti o chiedendo all'intelligenza artificiale.
                </p>
                <button
                    onClick={handleAuth}
                    disabled={gcalState === 'authenticating'}
                    className="bg-primary hover:bg-primary/90 disabled:bg-muted text-primary-foreground font-bold py-3 px-6 rounded-full inline-flex items-center space-x-3 transition-all duration-300"
                >
                    {gcalState === 'authenticating' ? <Loader className="h-5 w-5"/> : <GoogleIcon className="h-5 w-5" />}
                    <span>Connetti Google Calendar</span>
                </button>
            </div>
        );
    }

    if (gcalState === 'loading') {
        return <div className="text-center p-8"><Loader /><p className="mt-4 text-muted-foreground">Caricamento dati...</p></div>;
    }

    if (gcalState === 'error' && error) {
         return (
             <div className="text-center p-8 bg-destructive/10 border border-destructive/30 rounded-lg">
                <h3 className="font-bold text-lg text-destructive-foreground/90">{error.title}</h3>
                <p className="text-sm mt-2 text-destructive-foreground/80">{error.message}</p>
                 <button onClick={handleAuth} className="mt-6 bg-primary hover:bg-primary/90 text-primary-foreground font-bold py-2 px-6 rounded-full">
                     Riprova Accesso
                 </button>
            </div>
         );
    }

    return (
        <div className="animate-fade-in space-y-8">
            <div>
                <p className="text-center text-muted-foreground mb-2">Accesso effettuato come <span className="font-semibold text-foreground">{user?.email}</span></p>
                <div className="max-w-3xl mx-auto bg-card p-6 rounded-lg border border-border space-y-4">
                    <div>
                        <label htmlFor="calendar-select" className="block mb-2 text-sm font-medium text-muted-foreground">1. Scegli un calendario da analizzare</label>
                        <select
                           id="calendar-select"
                           value={selectedCalendarId}
                           onChange={(e) => setSelectedCalendarId(e.target.value)}
                           className="bg-input border border-border text-foreground text-sm rounded-lg focus:ring-ring focus:border-primary block w-full p-2.5"
                        >
                           {calendars.map(cal => <option key={cal.id} value={cal.id}>{cal.summary}</option>)}
                        </select>
                    </div>
                     <div>
                        <label htmlFor="ai-query" className="block mb-2 text-sm font-medium text-muted-foreground">2. Descrivi gli eventi da trovare</label>
                        <div className="relative">
                            <input
                                type="text"
                                id="ai-query"
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                                placeholder="Es: 'tutte le riunioni ricorrenti di sync del mese scorso' o 'eventi senza partecipanti'"
                                className="bg-input border border-border text-foreground text-sm rounded-lg focus:ring-ring focus:border-primary block w-full p-3 pl-10"
                            />
                            <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                                <SparklesIcon className="w-5 h-5 text-muted-foreground" />
                            </div>
                        </div>
                    </div>
                    <div className="text-center pt-2">
                         <button
                            onClick={handleSearch}
                            disabled={isSearching || !searchQuery.trim()}
                            className="bg-primary hover:bg-primary/90 disabled:bg-muted text-primary-foreground font-bold py-3 px-8 rounded-full inline-flex items-center space-x-3 transition-all duration-300"
                        >
                            {isSearching ? <Loader className="h-5 w-5"/> : <SearchIcon className="h-5 w-5" />}
                            <span>Trova Eventi</span>
                        </button>
                    </div>
                </div>
            </div>

            {isSearching && <div className="text-center py-4"><Loader /><p className="mt-2 text-muted-foreground">Ricerca in corso...</p></div>}

            {events.length > 0 && (
                <div className="max-w-3xl mx-auto animate-fade-in">
                    <h3 className="text-xl font-semibold mb-4 text-center">Risultati della Ricerca</h3>
                    <div className="bg-card border border-border rounded-lg p-4 space-y-3 max-h-96 overflow-y-auto">
                        {events.map(event => (
                            <div key={event.id} className="bg-secondary p-3 rounded-md flex justify-between items-center">
                                <div>
                                    <p className="font-semibold text-secondary-foreground">{event.summary}</p>
                                    <p className="text-sm text-muted-foreground">
                                        {new Date(event.start.dateTime || event.start.date || '').toLocaleString()}
                                    </p>
                                </div>
                                <a href={event.htmlLink} target="_blank" rel="noopener noreferrer" className="text-sm text-primary hover:underline">Vedi</a>
                            </div>
                        ))}
                    </div>
                     <div className="text-center mt-6">
                         <button
                            disabled // Abilitare dopo aver implementato la selezione
                            className="bg-destructive hover:bg-destructive/90 disabled:bg-muted text-destructive-foreground font-bold py-3 px-8 rounded-full inline-flex items-center space-x-3 transition-all duration-300"
                        >
                            <Trash2Icon className="h-5 w-5" />
                            <span>Elimina Selezionati (Prossimamente)</span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

