import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { ThemeCustomizer } from './components/ThemeCustomizer';
import metadata from './metadata.json';
import { Dashboard } from './components/Dashboard';
import { ImportView } from './components/ImportView';
import { CleanupView } from './components/CleanupView';
import { HelpModal } from './components/HelpModal';
import readmeContent from './README.md?raw';

export default function App() {
  const [page, setPage] = useState<'dashboard' | 'import' | 'cleanup'>('dashboard');
  const [isThemeCustomizerOpen, setThemeCustomizerOpen] = useState(false);
  const [isHelpOpen, setHelpOpen] = useState(false);
  const [appName, setAppName] = useState<string>('');
  const [appDescription, setAppDescription] = useState<string>('');

  useEffect(() => {
    setAppName(metadata.name || 'ForMa Calendar Suite');
    setAppDescription(metadata.description || 'Una suite intelligente per importare e pulire i tuoi calendari.');
  }, []);

  const renderPage = () => {
    switch (page) {
      case 'import':
        return <ImportView setPage={setPage} />;
      case 'cleanup':
        return <CleanupView setPage={setPage} />;
      case 'dashboard':
      default:
        return <Dashboard setPage={setPage} />;
    }
  };

  return (
    <div className="min-h-screen text-foreground p-4 sm:p-6 lg:p-8 flex flex-col items-center">
      <div className="w-full max-w-7xl mx-auto">
        <Header 
          appName={appName}
          description={appDescription}
          onGoHome={() => setPage('dashboard')} 
          showHomeButton={page !== 'dashboard'}
          onCustomizeTheme={() => setThemeCustomizerOpen(true)}
          onOpenHelp={() => setHelpOpen(true)}
        />
        <main className="mt-8">
          {renderPage()}
        </main>
      </div>
      <ThemeCustomizer 
        isOpen={isThemeCustomizerOpen} 
        onClose={() => setThemeCustomizerOpen(false)} 
      />
       <HelpModal 
        isOpen={isHelpOpen} 
        onClose={() => setHelpOpen(false)}
        content={readmeContent}
      />
    </div>
  );
}

import React, { useMemo } from 'react';
import { XIcon } from './Icons';

interface HelpModalProps {
  isOpen: boolean;
  onClose: () => void;
  content: string;
}

export const HelpModal: React.FC<HelpModalProps> = ({ isOpen, onClose, content }) => {

    const formattedContent = useMemo(() => {
        if (!content) return '';

        let html = content;

        // Process multiline blocks first (code blocks)
        html = html.replace(/```bash\n([\s\S]*?)```/gim, (match, p1) => {
            const escapedCode = p1.replace(/</g, "&lt;").replace(/>/g, "&gt;");
            return `<pre class="bg-secondary/50 p-4 rounded-md text-sm overflow-x-auto my-4 text-left"><code>${escapedCode}</code></pre>`;
        });

        const lines = html.split('\n');
        const newLines: string[] = [];
        let inList = false;

        for (const line of lines) {
            // Skip lines that have already been processed into <pre> blocks
            if (line.startsWith('<pre>')) {
                if (inList) { newLines.push('</ul>'); inList = false; }
                newLines.push(line);
                continue;
            }

            let processedLine = line
                .replace(/`([^`]+)`/gim, '<code class="bg-secondary/50 text-primary-foreground px-1 py-0.5 rounded-sm font-mono text-sm">$1</code>')
                .replace(/\*\*(.*?)\*\*/gim, '<strong>$1</strong>')
                .replace(/\[([^\]]+)\]\(([^)]+)\)/gim, '<a href="$2" target="_blank" rel="noopener noreferrer" class="text-primary hover:underline">$1</a>');

            if (processedLine.startsWith('### ')) {
                if (inList) { newLines.push('</ul>'); inList = false; }
                newLines.push(`<h3 class="text-xl font-semibold mt-4 mb-2">${processedLine.substring(4)}</h3>`);
            } else if (processedLine.startsWith('## ')) {
                if (inList) { newLines.push('</ul>'); inList = false; }
                newLines.push(`<h2 class="text-2xl font-bold mt-5 mb-2 pb-2 border-b border-border">${processedLine.substring(3)}</h2>`);
            } else if (processedLine.startsWith('# ')) {
