                newLines.push(`<h1 class="text-3xl font-bold mt-6 mb-3">${processedLine.substring(2)}</h1>`);
            } else if (processedLine.startsWith('---')) {
                if (inList) { newLines.push('</ul>'); inList = false; }
                newLines.push('<hr class="my-6 border-border" />');
