    const systemInstruction = getExtractionPrompt();

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents,
      config: {
          systemInstruction,
          responseMimeType: "application/json",
          responseSchema: {
              type: Type.ARRAY,
